//! The `beet` command-line interface: a scene runner.
//!
//! Like a game engine pressing play with no scene loaded, `beet` does nothing on
//! its own. On startup it looks for a `beet.json` in the cwd: absent, it prints a
//! welcome message and exits; present, it loads that scene (which supplies the
//! actual CLI) and watches the file for live reloads. The default CLI scene is
//! generated by the `default_cli` example.
use beet::prelude::*;
use beet_cli::prelude::*;

fn main() -> AppExit {
	App::new()
		.add_plugins((
			MinimalPlugins,
			LogPlugin::default(),
			ClientAppPlugin,
			// the runner must know every command type a `beet.json` can reference, so
			// the loaded scene's markers reconstruct their behaviour.
			CliCommandsPlugin,
			SceneManagementPlugin,
		))
		.run()
}
